const SCHEDULE_GAP_THRESHOLD_H = 26;
const BACKUP_STALE_THRESHOLD_H = 26;
const DISK_THRESHOLD_GB = 20;

function hoursBetween(olderIso, nowIso) {
  if (!olderIso) return Number.POSITIVE_INFINITY;
  const start = new Date(olderIso).getTime();
  const end = new Date(nowIso).getTime();
  if (!Number.isFinite(start)) return Number.POSITIVE_INFINITY;
  return (end - start) / 36e5;
}
function isoDay(isoString) {
  return String(isoString || new Date().toISOString()).slice(0, 10);
}
function warnEvent(warningType, subjectKey, severity, message, now, details) {
  const day = isoDay(now);
  return {
    event_type: 'warning',
    batch_run_id: 'wf-monitor_' + day,
    data: {
      warning_key: warningType + '|' + subjectKey + '|' + day,
      warning_type: warningType,
      severity,
      source_workflow: 'wf-monitor',
      subject_key: subjectKey,
      message,
      details: details || {},
    },
  };
}
function alertToWarningKey(alert, now) {
  const day = isoDay(now);
  switch (alert.type) {
    case 'CONTAINER_DOWN': return 'CONTAINER_DOWN|' + alert.container + '|' + day;
    case 'PG_UNREACHABLE': return 'PG_UNREACHABLE|postgres|' + day;
    case 'WORKFLOW_ERROR': return 'WORKFLOW_ERROR|' + (alert.workflowId || alert.workflowName) + '|' + day;
    case 'AUTH_ERROR': return 'AUTH_ERROR|' + (alert.workflowId || alert.workflowName) + '|' + day;
    case 'SCHEDULE_GAP': return 'SCHEDULE_GAP|' + alert.workflowKey + '|' + day;
    case 'LOW_DISK_SPACE': return 'LOW_DISK_SPACE|C_HOMELAB|' + day;
    case 'BACKUP_STALE': return 'BACKUP_STALE|backup|' + day;
    case 'ERROR_RATE_SPIKE': return 'ERROR_RATE_SPIKE|' + (alert.workflowId || alert.workflowName) + '|' + day;
    case 'WORKFLOW_DAILY_FAIL': return 'WORKFLOW_DAILY_FAIL|' + (alert.workflowId || alert.workflowName) + '|' + day;
    default: return null;
  }
}
function buildMonitoringReport(input) {
  const now = input.now || new Date().toISOString();
