    }
  }

  if (input.postgresReachable === false) {
    alerts.push({ type: 'PG_UNREACHABLE' });
    warningEvents.push(warnEvent('PG_UNREACHABLE', 'postgres', 'critical', 'PostgreSQL is unreachable', now));
  }

  for (const err of (input.authErrors || [])) {
    alerts.push({ type: 'AUTH_ERROR', workflowName: err.workflowName, workflowId: err.workflowId, nodeName: err.nodeName || null, credentialName: err.credentialName || null, errorAt: err.errorAt, errorMsg: err.errorMsg || null });
    const msgParts = ['Auth-Fehler in ' + err.workflowName];
    if (err.nodeName) msgParts.push('Node: ' + err.nodeName);
    if (err.credentialName) msgParts.push('Credential: ' + err.credentialName);
    if (err.errorMsg) msgParts.push('(' + err.errorMsg + ')');
    warningEvents.push(warnEvent('AUTH_ERROR', err.workflowId || err.workflowName, 'critical', msgParts.join(' - '), now, { workflowName: err.workflowName, nodeName: err.nodeName, credentialName: err.credentialName, errorAt: err.errorAt, errorMsg: err.errorMsg }));
  }

  for (const err of (input.workflowErrors || [])) {
    alerts.push({ type: 'WORKFLOW_ERROR', workflowName: err.workflowName, workflowId: err.workflowId, errorAt: err.errorAt });
    warningEvents.push(warnEvent('WORKFLOW_ERROR', err.workflowId || err.workflowName, 'warning', 'Workflow error in ' + err.workflowName + ' at ' + err.errorAt, now, { workflowName: err.workflowName, errorAt: err.errorAt }));
  }

  for (const [key, lastSuccess] of Object.entries(input.scheduleLastSuccess || {})) {
    const ageH = hoursBetween(lastSuccess, now);
    if (ageH > SCHEDULE_GAP_THRESHOLD_H) {
      alerts.push({ type: 'SCHEDULE_GAP', workflowKey: key, ageH, lastSuccessAt: lastSuccess });
      warningEvents.push(warnEvent('SCHEDULE_GAP', key, 'warning', 'Schedule gap: ' + key + ' last success ' + Math.round(ageH) + 'h ago (limit: ' + SCHEDULE_GAP_THRESHOLD_H + 'h)', now, { workflowKey: key, ageH, lastSuccessAt: lastSuccess || null }));
    }
  }

  if (input.diskFreeGb != null && input.diskFreeGb < DISK_THRESHOLD_GB) {
    alerts.push({ type: 'LOW_DISK_SPACE', freeGb: input.diskFreeGb, thresholdGb: DISK_THRESHOLD_GB });
    warningEvents.push(warnEvent('LOW_DISK_SPACE', 'C_HOMELAB', 'warning', 'Disk free ' + input.diskFreeGb + ' GB below threshold ' + DISK_THRESHOLD_GB + ' GB', now, { freeGb: input.diskFreeGb, thresholdGb: DISK_THRESHOLD_GB }));
  }

  for (const spike of (input.errorRateSpikes || [])) {
    alerts.push({ type: 'ERROR_RATE_SPIKE', workflowId: spike.workflowId, workflowName: spike.workflowName, errorCount: spike.errorCount, windowMinutes: spike.windowMinutes });
    warningEvents.push(warnEvent('ERROR_RATE_SPIKE', spike.workflowId || spike.workflowName, 'warning', 'Fehlerraten-Spitze: ' + spike.workflowName + ' - ' + spike.errorCount + ' Errors in ' + spike.windowMinutes + ' Min', now, { workflowName: spike.workflowName, errorCount: spike.errorCount, windowMinutes: spike.windowMinutes }));
  }

  for (const wf of (input.criticalWorkflowLastRuns || [])) {
    if (wf.lastStatus === 'error') {
      alerts.push({ type: 'WORKFLOW_DAILY_FAIL', workflowId: wf.workflowId, workflowName: wf.workflowName, lastRunAt: wf.lastRunAt });
      warningEvents.push(warnEvent('WORKFLOW_DAILY_FAIL', wf.workflowId || wf.workflowName, 'warning', 'Letzter Lauf fehlgeschlagen: ' + wf.workflowName, now, { workflowId: wf.workflowId, workflowName: wf.workflowName, lastRunAt: wf.lastRunAt }));
    }
  }

  const backupAgeH = hoursBetween(input.lastBackupOkAt, now);
  if (backupAgeH > BACKUP_STALE_THRESHOLD_H) {
    alerts.push({ type: 'BACKUP_STALE', ageH: backupAgeH, lastBackupOkAt: input.lastBackupOkAt || null });
    warningEvents.push(warnEvent('BACKUP_STALE', 'backup', 'warning', 'Backup stale: last BACKUP_OK ' + Math.round(backupAgeH) + 'h ago (limit: ' + BACKUP_STALE_THRESHOLD_H + 'h)', now, { ageH: backupAgeH, lastBackupOkAt: input.lastBackupOkAt || null }));
  }

  const existingKeys = new Set(input.existingWarningKeys || []);
  const newAlerts = alerts.filter(a => { const k = alertToWarningKey(a, now); return k === null || !existingKeys.has(k); });
  const mail = buildMail(newAlerts, now);
  return { status: alerts.length > 0 ? 'alert' : 'ok', alerts, warningEvents, mail, shouldSendMail: newAlerts.length > 0 };
}

function buildMail(alerts, now) {
  const day = isoDay(now);
  if (alerts.length === 0) {
    return { sendTo: 'PatrickZinke@gmx.net', subject: 'WF-Monitor ' + day + ': ok', text: 'WF-Monitor ' + day + ': alle Checks ok', html: '<pre>WF-Monitor ' + day + ': alle Checks ok</pre>' };
